[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
    @page {
        size: A4 portrait;
        margin: 7mm;
    }

    .print-format {
        font-family: Arial, sans-serif;
        font-size: 8px;
        color: #000;
        line-height: 1.2;
    }

    .dispensing-sheet {
        width: 100%;
        border: 1px solid #000;
    }

    .dispensing-sheet,
    .dispensing-sheet table {
        border-collapse: collapse;
        border-spacing: 0;
    }

    .dispensing-sheet table {
        width: 100%;
        table-layout: fixed;
    }

    .dispensing-sheet td,
    .dispensing-sheet th {
        border: 1px solid #000;
        padding: 3px 4px;
        vertical-align: middle;
        word-wrap: break-word;
    }

    .no-border {
        border: 0 !important;
    }

    .company-name {
        font-size: 9px;
        font-weight: bold;
        text-align: center;
        text-transform: uppercase;
    }

    .document-title {
        font-size: 14px;
        font-weight: bold;
        text-align: center;
    }

    .document-subtitle {
        font-size: 7px;
        text-align: center;
        padding-top: 2px;
    }

    .label-cell {
        font-weight: bold;
        background: #f2f2f2;
    }

    .value-cell {
        min-height: 16px;
    }

    .section-title {
        font-size: 9px;
        font-weight: bold;
        text-align: left;
        border-left: 0 !important;
        border-right: 0 !important;
        padding: 5px 2px !important;
    }

    .materials-table {
        width: 100%;
        table-layout: fixed;
        border-collapse: collapse;
    }

    .materials-table th {
        font-size: 6.5px;
        font-weight: bold;
        text-align: center;
        padding: 3px 1px;
        vertical-align: middle;
    }

    .materials-table td {
        font-size: 7px;
        padding: 3px 2px;
        height: 19px;
        vertical-align: middle;
    }

    .text-center {
        text-align: center;
    }

    .text-right {
        text-align: right;
    }

    .signature-table td {
        height: 65px;
        vertical-align: top;
        padding: 4px;
    }

    .signature-heading {
        font-weight: bold;
        text-align: center;
        border-bottom: 1px solid #000;
        padding-bottom: 4px;
        margin-bottom: 20px;
    }

    .signature-line {
        margin-top: 5px;
        font-size: 7px;
    }

    .footer-note {
        font-size: 6.5px;
        padding: 5px 3px;
        line-height: 1.3;
    }

    .page-break-avoid {
        page-break-inside: avoid;
    }
</style>

{# --------------------------------------------------------- #}
{# Dynamic values and fallbacks                              #}
{# --------------------------------------------------------- #}

{% set first_item = doc.items[0] if doc.items else none %}

{% set batch_no =
    first_item.batch_no
    if first_item and first_item.batch_no
    else ""
%}

{% set product_name =
    doc.custom_product_name
    or doc.get("product_name")
    or ""
%}

{% if not product_name and doc.work_order %}
    {% set product_name = frappe.db.get_value(
        "Work Order",
        doc.work_order,
        "production_item"
    ) or "" %}
{% endif %}

{% if not product_name and first_item %}
    {% set product_name = first_item.item_name or first_item.item_code or "" %}
{% endif %}

{% set generic_name =
    doc.custom_generic_name
    or doc.get("generic_name")
    or ""
%}

{% set label_claim =
    doc.custom_label_claim
    or doc.get("label_claim")
    or ""
%}

{% set batch_size =
    doc.custom_batch_size
    or doc.get("batch_size")
    or doc.fg_completed_qty
    or ""
%}

{% set manufacturing_date = "" %}
{% set expiry_date = "" %}

{% if batch_no %}
    {% set manufacturing_date = frappe.db.get_value(
        "Batch",
        batch_no,
        "manufacturing_date"
    ) or "" %}

    {% set expiry_date = frappe.db.get_value(
        "Batch",
        batch_no,
        "expiry_date"
    ) or "" %}
{% endif %}

<div class="dispensing-sheet">

    <!-- Header -->
    <table>
        <tr>
            <td style="width:25%; height:45px;">
                <div class="company-name">
                    {{ doc.company or "" }}
                </div>
            </td>

            <td style="width:50%;">
                <div class="document-title">DISPENSING SHEET</div>
                <div class="document-subtitle">
                    Raw Materials Dispensing Record
                </div>
            </td>

            <td style="width:25%; padding:2px;">
                <table style="border:0;">
                    <tr>
                        <td class="no-border" style="width:43%; padding:1px;">
                            <strong>Format No.</strong>
                        </td>
                        <td class="no-border" style="padding:1px;">
                            {{ doc.custom_format_no or "" }}
                        </td>
                    </tr>
                    <tr>
                        <td class="no-border" style="padding:1px;">
                            <strong>Version No.</strong>
                        </td>
                        <td class="no-border" style="padding:1px;">
                            {{ doc.custom_version_no or "" }}
                        </td>
                    </tr>
                    <tr>
                        <td class="no-border" style="padding:1px;">
                            <strong>Effective Date</strong>
                        </td>
                        <td class="no-border" style="padding:1px;">
                            {% if doc.custom_effective_date %}
                                {{ frappe.utils.formatdate(doc.custom_effective_date, "dd-MM-yyyy") }}
                            {% endif %}
                        </td>
                    </tr>
                </table>
            </td>
        </tr>
    </table>

    <!-- BCP/BMR row -->
    <table>
        <tr>
            <td style="width:15%;" class="label-cell">BCP Ref.</td>
            <td style="width:35%;" class="value-cell">
                {{ doc.custom_bcp_reference or doc.name or "" }}
            </td>

            <td style="width:15%;" class="label-cell">BMR No.</td>
            <td style="width:35%;" class="value-cell">
                {{ doc.custom_bmr_no or doc.work_order or "" }}
            </td>
        </tr>
    </table>

    <!-- Product and batch information -->
    <table>
        <tr>
            <td style="width:18%;" class="label-cell">Product Name</td>
            <td style="width:32%;" class="value-cell">
                {{ product_name }}
            </td>

            <td style="width:18%;" class="label-cell">Batch No.</td>
            <td style="width:32%;" class="value-cell">
                {{ batch_no }}
            </td>
        </tr>

        <tr>
            <td class="label-cell">Generic Name</td>
            <td class="value-cell">
                {{ generic_name }}
            </td>

            <td class="label-cell">Batch Size</td>
            <td class="value-cell">
                {{ batch_size }}
                {% if doc.stock_uom %}
                    {{ doc.stock_uom }}
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="label-cell">Label Claim</td>
            <td class="value-cell">
                {{ label_claim }}
            </td>

            <td class="label-cell">Dispensing Date</td>
            <td class="value-cell">
                {% if doc.posting_date %}
                    {{ frappe.utils.formatdate(doc.posting_date, "dd-MM-yyyy") }}
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="label-cell">Mfg. Date</td>
            <td class="value-cell">
                {% if manufacturing_date %}
                    {{ frappe.utils.formatdate(manufacturing_date, "dd-MM-yyyy") }}
                {% endif %}
            </td>

            <td class="label-cell">Exp. Date</td>
            <td class="value-cell">
                {% if expiry_date %}
                    {{ frappe.utils.formatdate(expiry_date, "dd-MM-yyyy") }}
                {% endif %}
            </td>
        </tr>
    </table>

    <!-- Dispensing conditions -->
    <table>
        <tr>
            <td style="width:18%;" class="label-cell">Dispensing Booth No.</td>
            <td style="width:32%;" class="value-cell">
                {{ doc.custom_dispensing_booth_no or "" }}
            </td>

            <td style="width:18%;" class="label-cell">RLAF ID</td>
            <td style="width:32%;" class="value-cell">
                {{ doc.custom_rlaf_id or "" }}
            </td>
        </tr>

        <tr>
            <td class="label-cell">Temperature (°C)</td>
            <td class="value-cell">
                {{ doc.custom_temperature or "" }}
            </td>

            <td class="label-cell">Rel. Humidity (%)</td>
            <td class="value-cell">
                {{ doc.custom_relative_humidity or "" }}
            </td>
        </tr>

        <tr>
            <td class="label-cell">Balance ID</td>
            <td class="value-cell">
                {{ doc.custom_balance_id or "" }}
            </td>

            <td class="label-cell">Balance Calibrated</td>
            <td class="value-cell">
                {% if doc.custom_balance_calibrated %}
                    Yes
                {% else %}
                    No
                {% endif %}
            </td>
        </tr>
    </table>

    <div class="section-title">Materials Dispensed</div>

    <!-- Materials table -->
    <table class="materials-table">
        <thead>
            <tr>
                <th style="width:4%;">S.No.</th>
                <th style="width:13%;">Material Code</th>
                <th style="width:23%;">Material Name</th>
                <th style="width:10%;">A.R. / A.R. No.</th>
                <th style="width:10%;">Std. Qty / Batch</th>
                <th style="width:10%;">Qty Dispensed</th>
                <th style="width:6%;">UOM</th>
                <th style="width:7%;">No. of Cont.</th>
                <th style="width:8%;">Date</th>
                <th style="width:9%;">Checked By</th>
            </tr>
        </thead>

        <tbody>
            {% for row in doc.items %}
                <tr>
                    <td class="text-center">{{ loop.index }}</td>

                    <td>
                        {{ row.item_code or "" }}
                    </td>

                    <td>
                        {{ row.item_name or "" }}
                    </td>

                    <td class="text-center">
                        {{ row.custom_ar_no or row.get("ar_no") or "" }}
                    </td>

                    <td class="text-right">
                        {% if row.custom_required_qty %}
                            {{ frappe.utils.fmt_money(
                                row.custom_required_qty,
                                precision=3,
                                currency=""
                            ) }}
                        {% elif row.transfer_qty %}
                            {{ frappe.utils.fmt_money(
                                row.transfer_qty,
                                precision=3,
                                currency=""
                            ) }}
                        {% else %}
                            {{ frappe.utils.fmt_money(
                                row.qty or 0,
                                precision=3,
                                currency=""
                            ) }}
                        {% endif %}
                    </td>

                    <td class="text-right">
                        {{ frappe.utils.fmt_money(
                            row.qty or 0,
                            precision=3,
                            currency=""
                        ) }}
                    </td>

                    <td class="text-center">
                        {{ row.uom or row.stock_uom or "" }}
                    </td>

                    <td class="text-center">
                        {{ row.custom_no_of_containers or "" }}
                    </td>

                    <td class="text-center">
                        {% if row.custom_dispensing_date %}
                            {{ frappe.utils.formatdate(
                                row.custom_dispensing_date,
                                "dd-MM-yyyy"
                            ) }}
                        {% else %}
                            {{ frappe.utils.formatdate(
                                doc.posting_date,
                                "dd-MM-yyyy"
                            ) }}
                        {% endif %}
                    </td>

                    <td>
                        {{ row.custom_checked_by or "" }}
                    </td>
                </tr>
            {% endfor %}

                {% for row in doc.items %}
                    <tr>
                        <td class="text-center">{{ loop.index }}</td>
                        <td>{{ row.item_code or "" }}</td>
                        <td>{{ row.item_name or "" }}</td>
                        <td class="text-center">{{ row.custom_ar_no or "" }}</td>
                        <td class="text-right">{{ row.custom_required_qty or row.transfer_qty or row.qty or 0 }}</td>
                        <td class="text-right">{{ row.qty or 0 }}</td>
                        <td class="text-center">{{ row.uom or row.stock_uom or "" }}</td>
                        <td class="text-center">{{ row.custom_no_of_containers or "" }}</td>
                        <td class="text-center">
                            {% if row.custom_dispensing_date %}
                                {{ frappe.utils.formatdate(row.custom_dispensing_date, "dd-MM-yyyy") }}
                            {% elif doc.posting_date %}
                                {{ frappe.utils.formatdate(doc.posting_date, "dd-MM-yyyy") }}
                            {% endif %}
                        </td>
                        <td>{{ row.custom_checked_by or "" }}</td>
                    </tr>
                {% endfor %}

        </tbody>
    </table>

    <!-- Signature section -->
    <table class="signature-table page-break-avoid">
        <tr>
            <td style="width:33.33%;">
                <div class="signature-heading">
                    Dispensed By (Production)
                </div>

                <div class="signature-line">
                    Name:
                    {{ doc.custom_dispensed_by_name or "" }}
                </div>

                <div class="signature-line">
                    Sign:
                </div>

                <div class="signature-line">
                    Date:
                    {% if doc.custom_dispensed_by_date %}
                        {{ frappe.utils.formatdate(
                            doc.custom_dispensed_by_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% endif %}
                </div>
            </td>

            <td style="width:33.33%;">
                <div class="signature-heading">
                    Checked By (Production)
                </div>

                <div class="signature-line">
                    Name:
                    {{ doc.custom_checked_by_name or "" }}
                </div>

                <div class="signature-line">
                    Sign:
                </div>

                <div class="signature-line">
                    Date:
                    {% if doc.custom_checked_by_date %}
                        {{ frappe.utils.formatdate(
                            doc.custom_checked_by_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% endif %}
                </div>
            </td>

            <td style="width:33.33%;">
                <div class="signature-heading">
                    Verified By (QA)
                </div>

                <div class="signature-line">
                    Name:
                    {{ doc.custom_verified_by_name or "" }}
                </div>

                <div class="signature-line">
                    Sign:
                </div>

                <div class="signature-line">
                    Date:
                    {% if doc.custom_verified_by_date %}
                        {{ frappe.utils.formatdate(
                            doc.custom_verified_by_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% endif %}
                </div>
            </td>
        </tr>
    </table>

    <!-- Footer -->
    <div class="footer-note">
        <strong>Note:</strong>
        This is a controlled document. Entries must be made in indelible ink.
        Corrections shall be made with a single line, signed and dated.
        Verify balance calibration status and area environmental conditions
        before dispensing.
    </div>

</div>"}]
